.darma-loader-loading-io-22 {
      display: inline-grid;
      grid-template-columns: repeat(3, 10px);
      gap: 5px;
    }
    .darma-loader-loading-io-22 i {
      width: 10px;
      height: 10px;
      border-radius: 4px;
      background: var(--loader-color, #f97316);
      animation: darma-loader-loading-io-22-gridFlash 1.05s ease-in-out infinite;
    }
    .darma-loader-loading-io-22 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-22 i:nth-child(2) { animation-delay: 0.08s; }
.darma-loader-loading-io-22 i:nth-child(3) { animation-delay: 0.16s; }
.darma-loader-loading-io-22 i:nth-child(4) { animation-delay: 0.08s; }
.darma-loader-loading-io-22 i:nth-child(5) { animation-delay: 0.16s; }
.darma-loader-loading-io-22 i:nth-child(6) { animation-delay: 0.24s; }
.darma-loader-loading-io-22 i:nth-child(7) { animation-delay: 0.16s; }
.darma-loader-loading-io-22 i:nth-child(8) { animation-delay: 0.24s; }
.darma-loader-loading-io-22 i:nth-child(9) { animation-delay: 0.32s; }
    @keyframes darma-loader-loading-io-22-gridFlash { 0%, 70%, 100% { opacity: .25; transform: scale(.75); } 35% { opacity: 1; transform: scale(1); } }

